import anthropic, json

client = anthropic.Anthropic()

def get_current_time() -> str:
    from datetime import datetime, timezone
    return datetime.now(timezone.utc).strftime("%H:%M UTC")

tools = [{
    "name": "get_current_time",
    "description": "Get the current UTC time.",
    "input_schema": {"type": "object", "properties": {}, "required": []}
}]

# Turn 1: user asks
messages = [{"role": "user", "content": "What time is it?"}]

# Turn 2: Claude responds with tool_use
response = client.messages.create(
    model="claude-sonnet-4-6", max_tokens=256, tools=tools, messages=messages
)
# response.stop_reason == "tool_use"

# Append the assistant message (contains the tool_use block)
messages.append({"role": "assistant", "content": response.content})

# Turn 3: user message containing tool_result(s)
results = []
for block in response.content:
    if block.type == "tool_use":
        output = get_current_time()
        results.append({
            "type": "tool_result",
            "tool_use_id": block.id,   # must match exactly
            "content": output
        })

messages.append({"role": "user", "content": results})

# Turn 4: Claude reads the result and answers
final = client.messages.create(
    model="claude-sonnet-4-6", max_tokens=256, tools=tools, messages=messages
)
print(final.content[0].text)   # "The current time is 10:32 UTC."
print(messages)                 # shows full 4-message conversation

# The "content" field in tool_result accepts three formats:

# 1. Plain string — most common
result_plain = {
    "type": "tool_result",
    "tool_use_id": block.id,
    "content": "19°C, partly cloudy"
}

# 2. JSON string — structured data the model can parse field-by-field
result_json = {
    "type": "tool_result",
    "tool_use_id": block.id,
    "content": json.dumps({
        "temperature": 19,
        "unit": "celsius",
        "condition": "partly cloudy",
        "humidity": 62
    })
}

# 3. List of content blocks — text + image
import base64
result_rich = {
    "type": "tool_result",
    "tool_use_id": block.id,
    "content": [
        {"type": "text", "text": "Current weather in London: 19°C, partly cloudy."},
        {
            "type": "image",
            "source": {
                "type": "base64",
                "media_type": "image/png",
                "data": base64.b64encode(chart_png_bytes).decode()
            }
        }
    ]
}

# After returning results, Claude may call MORE tools in the next turn.
# The loop continues until stop_reason is "end_turn".

def run_agent(user_msg: str) -> str:
    messages = [{"role": "user", "content": user_msg}]
    MAX_TURNS = 10

    for _ in range(MAX_TURNS):
        response = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=2048, tools=tools, messages=messages
        )

        if response.stop_reason == "end_turn":
            return next((b.text for b in response.content if hasattr(b, "text")), "")

        messages.append({"role": "assistant", "content": response.content})

        results = []
        for block in response.content:
            if block.type == "tool_use":
                fn = TOOL_REGISTRY.get(block.name)
                try:
                    output = json.dumps(fn(**block.input)) if fn else json.dumps({"error": "unknown"})
                    results.append({"type": "tool_result", "tool_use_id": block.id, "content": output})
                except Exception as e:
                    results.append({"type": "tool_result", "tool_use_id": block.id,
                                    "content": str(e), "is_error": True})

        messages.append({"role": "user", "content": results})

    return "Max turns reached."

# When parallel tools are called and some succeed / some fail,
# return all results — both successes and failures — in the same message.
# Never omit a result for a failed tool.

import concurrent.futures, json

def execute_all_parallel(tool_blocks: list, registry: dict, timeout: float = 10.0) -> list:
    results = []
    with concurrent.futures.ThreadPoolExecutor() as pool:
        futures = {}
        for block in tool_blocks:
            fn = registry.get(block.name)
            if fn is None:
                # Known failure — no need to submit
                results.append({
                    "type": "tool_result", "tool_use_id": block.id,
                    "content": f"Unknown tool: {block.name}", "is_error": True
                })
                continue
            futures[pool.submit(fn, **block.input)] = block

        for future, block in futures.items():
            try:
                output = future.result(timeout=timeout)
                results.append({
                    "type": "tool_result", "tool_use_id": block.id,
                    "content": json.dumps(output)
                })
            except concurrent.futures.TimeoutError:
                results.append({
                    "type": "tool_result", "tool_use_id": block.id,
                    "content": f"Timeout after {timeout}s", "is_error": True
                })
            except Exception as e:
                results.append({
                    "type": "tool_result", "tool_use_id": block.id,
                    "content": str(e), "is_error": True
                })
    return results

# Tool results accumulate in message history.
# After many turns, old results bloat the context and slow down the model.
# Prune tool_result content (not the blocks themselves) after they are used.

def prune_old_tool_results(messages: list[dict], keep_last_n_turns: int = 3) -> list[dict]:
    """Replace tool_result content beyond the last N assistant turns with a placeholder."""
    # Find indices of assistant turns in reverse order
    asst_turn_indices = [i for i, m in enumerate(messages) if m["role"] == "assistant"]

    if len(asst_turn_indices) <= keep_last_n_turns:
        return messages   # nothing to prune

    cutoff = asst_turn_indices[-keep_last_n_turns]  # keep only turns from here onward

    pruned = []
    for i, msg in enumerate(messages):
        if msg["role"] == "user" and isinstance(msg.get("content"), list) and i < cutoff:
            new_content = []
            for block in msg["content"]:
                if block.get("type") == "tool_result":
                    # Replace large content with a summary marker
                    block = {**block, "content": "[result pruned from history]"}
                new_content.append(block)
            pruned.append({**msg, "content": new_content})
        else:
            pruned.append(msg)

    return pruned

# Use before each API call in long-running agents
messages = prune_old_tool_results(messages, keep_last_n_turns=3)
